create table dirkspzm32.pzm_schichtarten (
    sa_name                 varchar2(100 char) not null enable,
    sa_beginn               date not null enable,
    sa_ende                 date not null enable,
    sa_wot_mo               number(*, 0) default 0 not null enable,
    sa_wot_di               number(*, 0) default 0 not null enable,
    sa_wot_mi               number(*, 0) default 0 not null enable,
    sa_wot_do               number(*, 0) default 0 not null enable,
    sa_wot_fr               number(*, 0) default 0 not null enable,
    sa_wot_sa               number(*, 0) default 0 not null enable,
    sa_wot_so               number(*, 0) default 0 not null enable,
    sa_std_pro_tag          number(*, 12),
    sa_bemerkung            varchar2(255 char),
    sa_pause1_beginn        date,
    sa_pause1_ende          date,
    sa_pause1_dauer         number(*, 12),
    sa_pause1_unbez         number(*, 0) default 0,
    sa_pause2_beginn        date,
    sa_pause2_ende          date,
    sa_pause2_dauer         number(*, 12),
    sa_pause2_unbez         number(*, 0) default 0,
    sa_kurzname             varchar2(10 char) not null enable,
    sa_standard             varchar2(1 char) default 'F',
    flex_max_std_pro_tag    number(*, 12),
    calc_basis              varchar2(20 char) default 'FESTZ' not null enable,
    gleitz_pause1_arb_std   number(*, 12),
    gleitz_pause1_dauer_min number(*, 12),
    gleitz_pause2_arb_std   number(*, 12),
    gleitz_pause2_dauer_min number(*, 12),
    gleitz_pause3_arb_std   number(*, 12),
    gleitz_pause3_dauer_min number(*, 12),
    sa_ende_nachlauf_min    number(*, 12),
    gleitz_pause_dauer_min  number(*, 12),
    gleitz_pause_unbez      varchar2(1 char) default 'T' not null enable,
    gleitz_pause1_unbez     varchar2(1 char) default 'T' not null enable,
    gleitz_pause2_unbez     varchar2(1 char) default 'T' not null enable,
    gleitz_pause3_unbez     varchar2(1 char) default 'T' not null enable,
    sa_bewertung_beginn     number(*, 0) default 0 not null enable,
    created_date            date default sysdate not null enable,
    created_login_id        number(*, 0) default - 1 not null enable,
    last_change_date        date,
    last_change_login_id    number(*, 0)
);

alter table dirkspzm32.pzm_schichtarten
    add constraint chk_pzm_schichtarten_bewertung
        check ( sa_bewertung_beginn in ( 0, 1 ) ) enable;

alter table dirkspzm32.pzm_schichtarten
    add constraint pk_sa_name primary key ( sa_name )
        using index enable;

alter table dirkspzm32.pzm_schichtarten
    add constraint pzm_schichtarten_sa_standard
        check ( sa_standard in ( 'T', 'F' ) ) enable;

alter table dirkspzm32.pzm_schichtarten add constraint u_sa_kurzname unique ( sa_kurzname )
    using index enable;


